use axum::{extract::State, http::HeaderMap, Json};use crate::{actions::registry::execute, auth::require_auth, error::AppError, models::{ExecuteActionRequest, ExecuteActionResponse, WsEvent}, AppState};
pub async fn execute_action(State(state):State<AppState>, headers:HeaderMap, Json(req):Json<ExecuteActionRequest>)->Result<Json<ExecuteActionResponse>,AppError>{require_auth(&headers,&state).await?; execute(&state,&req).await?; let evt=WsEvent{event_type:"action_executed".into(),payload:serde_json::json!({"actionId":req.action_id,"ok":true})}; let _=state.ws_tx.send(evt); Ok(Json(ExecuteActionResponse{ok:true,executed_at:crate::models::now()}))}
